-- Enrichment marathon batch: webtrees, Weebly, Weechat, Weights and Biases, Wekan, WellSaid Labs, WeTransfer, WeWeb

-- ── webtrees ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, self-hosted genealogy software for building, editing, and sharing family trees collaboratively from GEDCOM data.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2010, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Dutch$q$, $q$Russian$q$]::text[],
  seo_title = COALESCE($q$webtrees Review: Free Open-Source Genealogy Software (2026)$q$, seo_title),
  seo_meta_description = COALESCE($q$See what webtrees offers: free self-hosted genealogy software with GEDCOM support, family tree charts, privacy controls, and 40+ languages. Features, pricing, FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$webtrees is a free, open-source, web-based genealogy application that lets individuals, families, and genealogical societies build, edit, and publish family trees on their own web server. First released around 2010 as a successor to the earlier PhpGedView project, webtrees is licensed under the GNU GPL version 3 and developed by a community of volunteer contributors from many countries. Because it is self-hosted rather than delivered as a SaaS product, using webtrees costs nothing beyond standard PHP and database web hosting (MySQL, MariaDB, PostgreSQL, or SQLite are supported), and users retain full ownership and control of their genealogical data rather than storing it with a commercial provider like Ancestry or MyHeritage. The software works from standard GEDCOM files (compatible with GEDCOM 5.5.1 and newer 7.x specifications), so trees created in desktop genealogy applications or exported from other online services can be imported directly. Core functionality includes full editing of individuals, families, sources, and media records; multi-user accounts so relatives around the world can collaborate on a shared tree; and granular, per-record privacy controls that can automatically restrict details about living individuals. webtrees generates a range of charts and reports, including pedigree, descendancy, relationship, fan, and family book views, along with timelines and statistics. It supports interactive maps (via Google Maps or similar services) to plot where ancestors were born, married, or died, and it includes media galleries for attaching scanned photos, certificates, and documents to tree records. The interface is available in more than 40 languages and supports diverse cultural naming conventions, including patronymic, matronymic, and surname-first traditions. webtrees is extensible through a module system and a selection of official and community-built themes, and it integrates research tools such as journals, to-do lists, and census assistants. It has no built-in commercial record-hint database like paid competitors, so it functions purely as a tree-building, editing, and publishing platform rather than a genealogical records search service. Typical users include genealogical societies hosting shared member trees, families publishing their history online, and individual researchers who prefer to self-host rather than depend on a subscription-based platform.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '61b1b0a8-fc36-4a65-86e4-2a1059a7c262';

