-- ── Weebly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Drag-and-drop website and online store builder, now owned by Square, aimed at small businesses and entrepreneurs.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from about $10/month billed annually)$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Spanish$q$, $q$French$q$, $q$German$q$, $q$Italian$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$Weebly Review 2026: Pricing, Features, and Square Integration$q$, seo_title),
  seo_meta_description = COALESCE($q$Weebly overview: drag-and-drop website builder pricing plans, built-in ecommerce, Square payments integration, pros, cons, and frequently asked questions.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Weebly is a drag-and-drop website and online store builder founded in 2006 by David Rusenko, Chris Fanini, and Dan Veltri, who began building the product while at Pennsylvania State University. The company is headquartered in San Francisco, California, and was acquired by payments company Square (now Block, Inc.) in 2018, which has since deepened Weebly's focus on ecommerce and payments for small businesses. Weebly targets non-technical small business owners, freelancers, and entrepreneurs who want to launch a website or online store quickly without writing code. The core product is a visual, drag-and-drop site editor with mobile-responsive themes, along with built-in ecommerce functionality that is available on every plan tier, including the permanent free plan, which is unusual among mainstream website builders. Because Weebly is owned by Square, it offers tight integration with Square's payment processing and point-of-sale system, letting merchants sync online and in-person sales, inventory, and customer data in one place. Weebly's pricing structure includes a free tier that carries Weebly and Square branding and does not support a custom domain, a Personal plan priced around $10 to $15 per month, a Professional plan around $12 per month billed annually that adds a free custom domain for the first year and Google Ads credit, and a Performance plan at roughly $26 per month for higher-volume stores that removes Weebly's platform transaction fee. Additional features include a free SSL certificate on all plans, basic SEO tools, email marketing capabilities, a blogging engine, and an app center for extending functionality with third-party integrations. Compared to more design-flexible builders like Webflow or Wix, Weebly trades some layout customization for simplicity and speed, making it best suited to straightforward small business or local service websites and modest online stores rather than complex, highly custom sites or large-scale ecommerce operations that might be better served by a platform like Shopify.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '0091d0a1-3952-450b-b212-e0a36e137352';

