-- ── Weechat ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, extensible terminal-based IRC client built for speed, scripting, and lightweight remote use.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$WeeChat Review: Free Open-Source Terminal IRC Client$q$, seo_title),
  seo_meta_description = COALESCE($q$WeeChat overview: free open-source, extensible ncurses IRC client with scripting support, SASL authentication, and a relay protocol for mobile clients.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WeeChat, styled by its project as WeeChat and commonly written weechat.org, is a free and open-source Internet Relay Chat client created by Sebastien Helleu in June 2003 out of a desire for an IRC client with features that were not available at the time. It is released under the GNU General Public License version 3 or later and has been in continuous active development since its creation, making it one of the longer-lived open-source IRC clients still in wide use. WeeChat is designed to be light, fast, and extensible, running primarily through a default ncurses terminal interface, though its relay plugin allows other interfaces, such as the Glowing Bear web client or mobile relay apps, to connect to a running WeeChat session. The core architecture separates a lightweight base from independent, individually loadable and unloadable plugins, with the IRC plugin being the most prominent, supporting multiple simultaneous servers and networks, proxy support, IPv6, SASL authentication, DCC file transfers, and a nicklist. WeeChat supports scripting in eight languages, including Python, Perl, Ruby, Lua, Tcl, Guile, JavaScript, and PHP, with a built-in script manager for browsing and installing community-written scripts that add features like notifications, logging, bots, and custom formatting. The interface supports 256 colors, customizable status bars, smart message filtering, and horizontal or vertical window splitting for monitoring multiple channels at once. WeeChat runs on most major platforms, including Linux, the BSDs, macOS, Solaris, Haiku, and Windows, and it is commonly run persistently on a remote server inside tmux or screen so users maintain an always-on IRC presence they can reconnect to from any device. As a terminal-based, keyboard-driven tool with a text-based configuration system, WeeChat has a steeper learning curve than graphical chat clients and is primarily aimed at developers, system administrators, and other technically inclined users who value speed, scriptability, and persistent remote sessions over a graphical interface. Because it is entirely free and open source, there is no pricing tier or commercial edition; all functionality is available to anyone who installs it.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ee6c8b88-f000-4f14-8c23-19ab2bda304c';

