-- ── Wekan ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Free, open-source, self-hosted Trello-style kanban board for team task and project management.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE(NULL, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Finnish$q$]::text[],
  seo_title = COALESCE($q$Wekan Review: Free Open-Source Kanban Board (Trello Alternative)$q$, seo_title),
  seo_meta_description = COALESCE($q$Wekan overview: free open-source, self-hosted Trello-style kanban board with Trello import, swimlanes, REST API, and GDPR-friendly self-hosting.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Wekan is a free, open-source kanban board application designed as a self-hosted alternative to Trello, letting teams manage tasks and projects on their own infrastructure rather than a third-party SaaS platform. It was originally created around 2015 by Maxime Quandalle under the name LibreBoard before being renamed Wekan, and since December 2016 the project has been led by maintainer Lauri Ojansivu in Finland, supported by a community of roughly 180 contributors. Wekan is built on a JavaScript stack using the Meteor framework for both its front end and back end, and it deploys through common methods including Docker containers and Snap packages, making it accessible to organizations that want to run it on their own servers or private cloud. Functionally, Wekan closely mirrors Trello's board, list, and card structure, and it supports direct import of existing Trello boards, which lowers the barrier for teams migrating away from a commercial SaaS product. Core features include drag-and-drop cards across lists, swimlanes for organizing work by category or team, labels, checklists, due dates, file attachments, comments, and user assignments, along with notifications for mentions and changes and templates for standardizing board structures across projects. Wekan supports both public and private boards with configurable visibility, and it exposes a REST API for integrating with other tools and building custom automations or webhooks. Because Wekan is self-hosted, organizations retain full control over where their data lives, which makes it a common choice for privacy-conscious teams, educational institutions, nonprofits, and government bodies that need to satisfy data sovereignty or GDPR requirements that a third-party SaaS kanban tool cannot guarantee. There is no official first-party hosted SaaS version of Wekan from the core project, so most users must install and maintain their own instance, though some third-party providers offer managed hosting or paid commercial support as an add-on. As open-source software, Wekan carries no license fees, and its cost is limited to the infrastructure and administrative time needed to run and maintain a self-hosted instance.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8d61482f-100a-4065-95f7-81efc054d452';

