  seo_title = COALESCE($q$WeTransfer Review 2026: Pricing Plans and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$WeTransfer overview: send large files by link or email, Free, Starter, and Ultimate plans, Portals for collaboration, pricing, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WeTransfer is a large file transfer and sharing service founded in 2009 by Rinke Visser, Bas Beerens, and Ronald Hans (also known as Nalden), and headquartered in Amsterdam, Netherlands. It was created to make sending large files, such as photos, videos, and design assets, as simple as possible without requiring recipients to create an account, and it became especially popular among creative professionals in design, photography, video, and marketing for sharing project files with clients and collaborators. The core product lets users upload files and send them either as a shareable download link or directly via email, with options for password protection, expiration windows, and download notifications to keep transfers secure and trackable. Beyond basic transfers, WeTransfer offers Portals, dedicated pages for collecting files or feedback from multiple people, and Reviews, a tool for gathering structured feedback and approvals on creative work, both aimed at agencies and freelancers managing client collaboration. As of WeTransfer's most recent pricing structure, the company operates a three-tier model: a Free plan that allows up to 10 transfers or 3GB of total transfer volume within any rolling 30-day period, with individual transfers capped at 2GB when sent without an account; a Starter plan priced at $8 per month that raises the rolling 30-day transfer volume to 300GB; and an Ultimate plan priced at $23 per month (or about $19 per month when billed annually) that removes the rolling volume cap entirely, supporting unlimited transfers of up to 1TB each, along with custom branding for transfer pages and emails and unlimited access to Portals and Reviews. This replaced an earlier Pro and Premium plan structure that was consolidated during a 2024 pricing overhaul. Because free transfers expire after a set period, WeTransfer functions primarily as a transfer tool rather than a long-term storage solution, though paid plans add persistent cloud storage alongside transfer capability. WeTransfer's combination of a frictionless free tier, a recognizable brand among creative professionals, and creative-collaboration add-ons like Portals and Reviews differentiates it from more enterprise-focused file-sharing and sync tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'de4e2a22-9bfb-45e0-b729-a24052dd6bfc';

