-- ── WeWeb ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$AI-assisted no-code and low-code platform for building production-ready web apps and internal tools on top of any backend.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from about $20/month for Essential)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Paris, France$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$WeWeb Review: No-Code Web App Builder Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$WeWeb overview: AI-assisted no-code web app builder with visual editor, native backend, Figma import, code export, pricing plans, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WeWeb is a no-code and low-code platform for building production-ready web applications, founded by Florian Briou, Marc Fabre, and Raphael Goldsztejn and headquartered in Paris, France, with the company generally cited as founded around 2020. WeWeb started as a visual front-end builder and drag-and-drop editor for creating dashboards, portals, and SaaS product interfaces on top of an existing backend, differentiating itself from all-in-one no-code app builders by focusing on the front end and connecting to virtually any data source, including Supabase, Xano, and custom REST or GraphQL APIs. The platform later expanded into a full-stack offering with its own native backend, called WeWeb Tables, a Postgres database with a spreadsheet-style user interface, auto-generated CRUD APIs, visual backend logic workflows, built-in authentication, and file storage, letting teams build an entire application, front end and back end, without leaving WeWeb. In 2025 the company introduced WeWeb AI, which generates user interface components and layouts from natural-language prompts and has been updated frequently since launch, and the platform also supports importing designs directly from Figma to speed up UI development. Developers can add custom logic and workflows visually in the editor, and for teams that want more control, WeWeb supports code export and GitHub sync so applications are not permanently locked into the platform. WeWeb's pricing is structured around seat plans that determine editor access and building capabilities, and separate hosting plans for deployment. The Free seat plan includes a limited AI token allowance and full access to the visual editor. The Essential plan, priced at roughly $16 to $20 per month depending on currency and promotional period, unlocks GitHub sync, a larger AI token allowance, and custom domain support. The Pro plan, at roughly $42 to $50 per month, adds unlimited seats and a larger AI token allocation for teams building and maintaining more complex projects together. A Partner plan, priced per user, is designed for agencies and freelancers doing client work, allowing them to join client workspaces for free, transfer projects, and earn referral commissions. Hosting plans, which are required in addition to a paid seat plan to deploy live applications, range from a free tier through Launch, Grow, and Scale tiers for higher-traffic production apps. WeWeb is commonly used by startups building internal tools and admin dashboards, no-code agencies building client-facing SaaS products, and product teams validating ideas through rapid prototyping.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f43a5180-ad73-4b48-95ac-b2cd02106791';

