INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$GEDCOM Import and Export$q$, $q$Full compatibility with GEDCOM 5.5.1 and newer files exported from desktop genealogy software or other online tree platforms.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Collaborative Multi-User Editing$q$, $q$Invite family members to create accounts and contribute research to a shared family tree with configurable permissions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Granular Privacy Controls$q$, $q$Per-record and per-user privacy settings that can automatically restrict sensitive details about living individuals.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Charts and Reports$q$, $q$Pedigree, descendancy, relationship, fan, family book, and timeline charts generated automatically from tree data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Media Galleries$q$, $q$Attach and organize photos, scanned certificates, and documents against individuals and events in the tree.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Interactive Maps$q$, $q$Plot ancestor birth, marriage, and death locations on a map to visualize family migration over time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Multi-Language Support$q$, $q$Interface available in more than 40 languages with support for diverse surname and naming conventions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Themes and Modules$q$, $q$Customizable themes and an extensible module system supported by the open-source community.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Completely free with no subscription or per-user fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Full data ownership since the tree is self-hosted on your own server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Strong multi-user collaboration with granular privacy controls$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Active open-source community with regular updates$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Wide GEDCOM compatibility with major desktop genealogy applications$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Requires technical setup on PHP and database web hosting, which is not beginner-friendly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$No built-in historical record hints or search database like paid competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Interface feels dated compared to modern commercial genealogy platforms$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$No official native mobile app; relies on a responsive web interface$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Is webtrees really free?$q$, $q$Yes, webtrees is released under the GPL version 3 license and is free to download, install, and modify. You only pay for your own web hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Do I need technical skills to install webtrees?$q$, $q$You need a web host that supports PHP and a database such as MySQL or PostgreSQL. Some genealogy-focused hosts offer simplified or one-click installs.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Can I import my existing family tree?$q$, $q$Yes, webtrees imports standard GEDCOM files exported from desktop genealogy software or other online tree services.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Does webtrees protect living relatives' privacy?$q$, $q$Yes, it includes granular privacy settings that can hide or mask details of living individuals by default.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Can multiple family members edit the same tree?$q$, $q$Yes, webtrees supports multi-user accounts with configurable permission levels for collaborative editing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$What languages does webtrees support?$q$, $q$The interface is available in more than 40 languages and supports various cultural naming and surname conventions.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Does webtrees offer historical record search like commercial services?$q$, $q$No, webtrees is a tree-building and publishing platform, not a historical records database.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Is there official support for webtrees?$q$, $q$Community support is available through forums, and some third-party hosting providers offer paid managed support.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Family Genealogy Societies$q$, $q$Societies can host a shared, moderated tree that members contribute to and research together over time.$q$, $q$Genealogical societies and hobbyist historians$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Personal Family Tree Publishing$q$, $q$Individuals publish their family history online for relatives to browse, explore, and add to.$q$, $q$Individuals and families$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Collaborative Research Projects$q$, $q$Multiple researchers edit one large shared tree, importing GEDCOM data from various sources.$q$, $q$Genealogy researchers and family history enthusiasts$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited family trees","Full GEDCOM import and export","Multi-user accounts and privacy controls","Community themes and modules","Requires self-hosting on PHP and database web hosting"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$overview$q$, $q$What Is webtrees$q$, 2, ARRAY[$q$webtrees is a free, open-source genealogy application that runs on your own web server, letting you build, edit, and publish family trees online. It grew out of the earlier PhpGedView project and has been maintained by an international community of volunteer developers since around 2010.$q$, $q$Because webtrees is self-hosted rather than a paid cloud service, there are no subscription fees and no third party controls your family data. All that is required is a web host running PHP with a supported database such as MySQL, MariaDB, PostgreSQL, or SQLite.$q$, $q$The software is built around the GEDCOM standard, the common file format used by nearly all genealogy programs, which makes it straightforward to import an existing tree from desktop software or another online service and continue building it in webtrees.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$webtrees supports multi-user collaboration, so several relatives can log in and contribute research to the same shared tree, each with configurable permission levels.$q$, $q$Privacy is handled through granular, per-record controls that can automatically hide sensitive details about living individuals, which matters for trees that will be viewed publicly online.$q$, $q$The platform produces a wide variety of charts and reports, including pedigree, descendancy, relationship, and fan charts, plus interactive maps that plot ancestral birth, marriage, and death locations, and media galleries for photos and scanned documents.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$webtrees itself is completely free to download, install, and use under the GPL version 3 license. There is no paid tier, subscription, or per-user fee for the software.$q$, $q$The only cost involved is standard web hosting for the PHP application and its database, which can range from a few dollars a month on shared hosting to more for dedicated or managed genealogy-specific hosting providers.$q$, $q$Some third-party companies offer managed webtrees hosting or paid support contracts for users who prefer not to self-manage the server, but these are optional add-ons rather than requirements from the webtrees project itself.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('61b1b0a8-fc36-4a65-86e4-2a1059a7c262', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Drag-and-Drop Editor$q$, $q$Visual site builder that lets users assemble pages without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Built-In Ecommerce$q$, $q$Sell physical and digital products directly from the site on any plan, including the free tier.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Square Payments and POS Integration$q$, $q$Sync online sales with Square's in-person point-of-sale and inventory systems.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Mobile-Responsive Themes$q$, $q$All Weebly themes automatically adapt to desktop, tablet, and mobile screens.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Basic SEO Tools$q$, $q$Editable meta titles, descriptions, and sitemap generation to help pages get indexed.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$App Center Integrations$q$, $q$Extend site functionality with third-party apps for marketing, forms, and more.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Email Marketing Tools$q$, $q$Built-in tools for sending marketing emails to site visitors and customers.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Free SSL Certificate$q$, $q$HTTPS encryption included by default on every plan, including free.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Easy to use drag-and-drop editor with a minimal learning curve$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Ecommerce features available even on the free plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Tight integration with Square payments and point-of-sale for small businesses already on Square$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Affordable entry-level pricing for paid plans$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Reliable hosting backed by Square and Block infrastructure$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Design flexibility is more limited than builders like Webflow or Wix for complex layouts$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Free plan displays Weebly and Square branding with no custom domain$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Fewer advanced ecommerce features than dedicated platforms like Shopify at scale$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Smaller app and plugin ecosystem compared to WordPress or Wix$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Is Weebly free?$q$, $q$Yes, there is a permanent free plan with Weebly branding and no custom domain; paid plans remove branding and add custom domain support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Who owns Weebly?$q$, $q$Weebly was acquired by Square, now part of Block, Inc., in 2018.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Can I sell products with Weebly?$q$, $q$Yes, built-in ecommerce is available on every plan, including the free tier.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Does Weebly integrate with Square point-of-sale?$q$, $q$Yes, Weebly has deep integration with Square, letting in-person and online sales sync through one system.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Is Weebly good for beginners?$q$, $q$Yes, its drag-and-drop editor is designed for non-technical users building their first website.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Can I use my own domain with Weebly?$q$, $q$Yes, on paid plans; the free plan uses a weebly.com subdomain.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Does Weebly support blogging?$q$, $q$Yes, a built-in blogging engine is included on Weebly sites.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Small Business Websites$q$, $q$Local service providers and small business owners build a professional site quickly without a developer.$q$, $q$Small business owners and local service providers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Simple Online Stores$q$, $q$Entrepreneurs selling a handful of products, especially those already using Square for payments, launch a store fast.$q$, $q$Entrepreneurs and small merchants using Square$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Personal and Portfolio Sites$q$, $q$Freelancers and individuals build a simple personal or portfolio website without coding.$q$, $q$Freelancers and individuals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Weebly subdomain","Basic templates","Limited storage","Built-in online store with platform fees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Personal$q$, $q$About $10 to $15/month$q$, $q$monthly or annual$q$, NULL, $q$["Custom domain support","More storage","Basic ecommerce"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Professional$q$, $q$About $12/month billed annually$q$, $q$annual$q$, NULL, $q$["Free custom domain for first year","Google Ads credit","Expanded ecommerce tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$Performance$q$, $q$$26/month$q$, $q$monthly$q$, NULL, $q$["No platform transaction fee","Advanced ecommerce features","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$overview$q$, $q$What Is Weebly$q$, 2, ARRAY[$q$Weebly is a drag-and-drop website builder that lets small business owners, freelancers, and entrepreneurs create websites and online stores without writing code. It was founded in 2006 and is now owned by Square, giving it particularly strong ties to Square's payments and point-of-sale ecosystem.$q$, $q$The platform is built around simplicity: a visual editor with mobile-responsive themes lets users assemble pages by dragging elements into place, making it a common choice for people building their first website.$q$, $q$Since the Square acquisition, ecommerce has become a central focus, with built-in online store functionality available on every plan, including the free tier.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Weebly's drag-and-drop editor covers page layout, image galleries, forms, and blogging, all wrapped in mobile-responsive themes that require no manual adjustment for different screen sizes.$q$, $q$Built-in ecommerce lets store owners list physical and digital products, manage inventory, and process payments without installing third-party apps, and it integrates directly with Square for in-person and online sales syncing.$q$, $q$Additional tools include basic SEO settings, email marketing features, an app center for extending site functionality, and a free SSL certificate included on every plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0091d0a1-3952-450b-b212-e0a36e137352', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Weebly offers a permanent free plan with Weebly and Square branding, limited storage, and no custom domain support, alongside three paid tiers.$q$, $q$The Personal plan runs roughly $10 to $15 per month, and the Professional plan is around $12 per month when billed annually, adding a free custom domain for the first year and Google Ads credit.$q$, $q$The top-tier Performance plan costs about $26 per month and is aimed at higher-volume online stores, removing Weebly's platform transaction fee on sales.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$ncurses Terminal Interface$q$, $q$Fast, keyboard-driven default interface, with optional web or GUI frontends via the relay plugin.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Multi-Server IRC Support$q$, $q$Connect to multiple IRC servers and networks simultaneously with proxy and IPv6 support.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Scripting in 8 Languages$q$, $q$Extend WeeChat with scripts written in Python, Perl, Ruby, Lua, Tcl, Guile, JavaScript, or PHP.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$SASL Authentication$q$, $q$Secure authentication support alongside SSL/TLS encrypted connections.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Smart Filtering and Window Splits$q$, $q$Filter noisy messages and split the terminal horizontally or vertically to monitor multiple channels.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$256-Color Support$q$, $q$Rich terminal color support and customizable status bars for a tailored interface.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Relay Protocol$q$, $q$Connect mobile or web clients such as Glowing Bear to a running WeeChat session remotely.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Plugin Architecture$q$, $q$A lightweight core with independent, individually loadable and unloadable plugins.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Completely free and open source under the GPL-3.0-or-later license$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Extremely lightweight, fast, and low resource usage$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Highly scriptable and extensible for power users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Runs persistently on remote servers via tmux or screen for an always-on IRC presence$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Long track record of active development since 2003$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Steep learning curve for users unfamiliar with terminal-based tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$No native graphical interface; relies on ncurses or third-party relay clients$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Primarily focused on IRC, with other protocols requiring community plugins or bridges$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Text and command-based configuration can be intimidating for beginners$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Is WeeChat free?$q$, $q$Yes, WeeChat is entirely free and open source under the GPL-3.0-or-later license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$What platforms does WeeChat run on?$q$, $q$Linux, macOS, the BSDs, Windows, and other Unix-like systems including Solaris and Haiku.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Can I use WeeChat on mobile?$q$, $q$Not natively, but its relay protocol supports mobile and web clients such as Glowing Bear that connect to a running WeeChat session.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Does WeeChat support scripting?$q$, $q$Yes, in Python, Perl, Ruby, Lua, Tcl, Guile, JavaScript, and PHP, with a built-in script manager.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Is WeeChat only for IRC?$q$, $q$Its core is protocol-agnostic, but the built-in and primary supported plugin is for IRC; other protocols require community plugins or bridges.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Who created WeeChat?$q$, $q$Sebastien Helleu created WeeChat in June 2003, and it continues to be actively developed by its open-source community.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Does WeeChat support secure connections?$q$, $q$Yes, including SSL/TLS encryption and SASL authentication.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Persistent Remote IRC Sessions$q$, $q$Run WeeChat on a remote server inside tmux or screen for an always-on IRC presence reachable from any device.$q$, $q$Developers and system administrators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Scripted and Automated IRC Tools$q$, $q$Build bots, notification hooks, and custom automation using WeeChat's multi-language scripting API.$q$, $q$Power users and script developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Lightweight Client for Open-Source Communities$q$, $q$Communicate efficiently in fast-moving open-source project channels using a low-overhead terminal client.$q$, $q$Open-source maintainers and contributors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full IRC client functionality","Scripting API in 8 languages","Relay plugin for remote and mobile access","Community plugins and themes"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$overview$q$, $q$What Is WeeChat$q$, 2, ARRAY[$q$WeeChat is a free, open-source Internet Relay Chat client created in 2003 and designed to be light, fast, and highly extensible. It runs primarily through a terminal-based ncurses interface, making it popular with developers and system administrators who prefer keyboard-driven, text-based tools.$q$, $q$Its plugin architecture separates a small core from independently loadable plugins, the most important of which handles IRC connectivity, while a relay plugin lets other interfaces, including web and mobile clients, connect to a running WeeChat session remotely.$q$, $q$WeeChat is commonly run on a remote server inside a terminal multiplexer like tmux or screen, giving users a persistent, always-connected IRC presence they can reattach to from any device.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The IRC plugin supports multiple simultaneous servers and networks, proxy support, IPv6, SASL authentication, DCC transfers, and a nicklist, covering the functionality most IRC power users need.$q$, $q$Scripting support spans eight languages, including Python, Perl, Ruby, Lua, Tcl, Guile, JavaScript, and PHP, with a built-in script manager for browsing and installing community scripts that add bots, notifications, and custom behavior.$q$, $q$The interface offers 256-color support, customizable status bars, smart filtering, and horizontal or vertical window splits so multiple channels can be monitored at once.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WeeChat is entirely free and open source under the GPL-3.0-or-later license, with no paid tier, subscription, or commercial edition.$q$, $q$All core functionality, plugins, and scripting capabilities are available to anyone who downloads and installs the software.$q$, $q$The only associated cost is optional: hosting a remote server if a user chooses to run WeeChat persistently in the cloud rather than locally.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ee6c8b88-f000-4f14-8c23-19ab2bda304c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
