INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Collaborative Reports$q$, $q$Shareable dashboards and reports that let teams document and discuss experiment results.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Hyperparameter Sweeps$q$, $q$Automated hyperparameter optimization to find the best-performing model configurations.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Artifacts and Dataset Versioning$q$, $q$Track datasets, models, and pipeline lineage across the machine learning lifecycle.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Framework Integrations$q$, $q$Native support for PyTorch, TensorFlow, Keras, Hugging Face, scikit-learn, OpenAI, and LangChain.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Enterprise Security$q$, $q$Single sign-on, HIPAA compliance, and self-hosted or single-tenant deployment options for enterprise customers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Industry-standard experiment tracking used widely across research and enterprise ML teams$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Deep, ready-made integrations with major ML frameworks and tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Generous free tier for individuals and academic researchers$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Extends beyond model training into LLM and GenAI application observability via Weave$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Strong collaboration features including shared dashboards and reports$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Costs scale quickly for teams needing more storage or data ingestion$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Learning curve for advanced features such as sweeps and artifact lineage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Self-hosted and enterprise deployment requires more setup and custom pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Free tier explicitly prohibits corporate or commercial use$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Is Weights and Biases free?$q$, $q$Yes, there is a free tier for individuals and academic use with 5GB of monthly storage, but corporate use requires a paid plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Who founded Weights and Biases?$q$, $q$Lukas Biewald, Chris Van Pelt, and Shawn Lewis founded the company in 2017.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$What is Weave in Weights and Biases?$q$, $q$Weave is a toolkit within the platform for tracing, evaluating, and monitoring LLM and GenAI applications.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Does Weights and Biases support self-hosting?$q$, $q$Yes, self-hosted and single-tenant enterprise deployment options are available.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$What frameworks does it integrate with?$q$, $q$PyTorch, TensorFlow, Keras, Hugging Face, scikit-learn, OpenAI, LangChain, and other common ML tools.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Is there an academic discount?$q$, $q$Yes, a free Pro-tier academic license is available for qualifying students and researchers.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$What company owns Weights and Biases now?$q$, $q$Weights and Biases became part of CoreWeave.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Does it support hyperparameter tuning?$q$, $q$Yes, through built-in Sweeps for automated hyperparameter optimization.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Machine Learning Experiment Tracking$q$, $q$Log, visualize, and compare model training runs to iterate faster on model performance.$q$, $q$ML research teams and data scientists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$LLM Application Evaluation and Monitoring$q$, $q$Trace, evaluate, and score prompts and model outputs for generative AI applications using Weave.$q$, $q$GenAI and LLM application developers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Enterprise Model Governance$q$, $q$Version, register, and audit models and datasets across large teams with security and compliance controls.$q$, $q$Enterprises building and deploying models at scale$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["5GB/month storage","Up to 5 model seats","AI evaluations, tracing, and scorers","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Pro$q$, $q$From $60/month$q$, $q$monthly$q$, NULL, $q$["Up to 10 model seats","Unlimited teams","Priority email and chat support","100GB/month storage","CI/CD automations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Single-tenant deployment","HIPAA compliance","SSO and automated provisioning","Custom roles and audit logs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$overview$q$, $q$What Is Weights and Biases$q$, 2, ARRAY[$q$Weights and Biases is an AI developer platform used by machine learning and generative AI teams to track experiments, manage model versions, and evaluate AI applications. It was founded in 2017 by Lukas Biewald, Chris Van Pelt, and Shawn Lewis and is headquartered in San Francisco.$q$, $q$What began as an experiment tracking tool for model training has grown into a broader MLOps platform, now spanning traditional model development as well as large language model application evaluation through its Weave product line.$q$, $q$The platform is used by both individual researchers and enterprise ML teams, with deep integrations into the tools and frameworks that make up a typical machine learning workflow.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Experiment tracking lets teams log metrics, hyperparameters, and system information during training, then compare runs visually to understand what changes improve model performance.$q$, $q$The Model Registry adds versioning, lineage tracking, and governance for models and datasets, while Weave brings tracing, evaluation, and scoring capabilities purpose-built for LLM and GenAI applications.$q$, $q$Sweeps automate hyperparameter optimization, and native integrations with PyTorch, TensorFlow, Hugging Face, OpenAI, and LangChain let teams adopt the platform without changing their existing stack.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7c66ab08-e955-4517-83cb-ca812af3c38d', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$A free tier is available for individual and academic use, including unlimited projects and teams and 5GB of monthly storage, though it prohibits corporate use.$q$, $q$The Pro plan starts at $60 per month and targets early-stage teams under 50 employees, adding more model seats, unlimited team collaboration, priority support, and larger storage and data ingestion allowances, with overage storage billed at $0.03 per gigabyte.$q$, $q$Enterprise plans are custom-priced and billed annually, adding single-tenant deployment, HIPAA compliance, SSO, custom roles, and audit logs, and a self-hosted deployment option is available for organizations with stricter data residency needs.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Kanban Boards, Lists, and Cards$q$, $q$Drag-and-drop task management with a board, list, and card structure familiar to Trello users.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Trello Import$q$, $q$Import existing Trello boards directly when creating a new Wekan board.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Self-Hosted Deployment$q$, $q$Deploy via Docker, Snap, or other self-hosted methods to keep full control over infrastructure and data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Swimlanes and Custom Fields$q$, $q$Organize boards with swimlanes and custom fields for more advanced workflow structuring.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Due Dates, Checklists, and Attachments$q$, $q$Track deadlines, subtasks, and file attachments directly on cards.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Notifications$q$, $q$Email and in-app notifications for mentions, assignments, and board changes.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Public and Private Boards$q$, $q$Configurable visibility and permissions to control who can view or edit each board.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$REST API$q$, $q$Programmatic access for integrations, webhooks, and custom automations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Completely free and open source with no per-user licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Full data control through self-hosting, useful for privacy and GDPR-sensitive organizations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Familiar Trello-like interface that eases migration from Trello$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Active community and frequent releases$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Can run on modest hardware or small servers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Requires self-hosting and server maintenance with no fully managed first-party SaaS option$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Interface feels less polished than commercial alternatives like Trello or Asana$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Smaller app and integration ecosystem than commercial competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Commercial support is a limited, paid add-on rather than a built-in offering$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Is Wekan free?$q$, $q$Yes, Wekan is open source and free to self-host, with no license fees for the software.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Can I import boards from Trello?$q$, $q$Yes, Wekan supports importing existing Trello boards directly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Do I need to self-host Wekan?$q$, $q$Typically yes, since there is no official first-party hosted SaaS version, though some third parties offer managed hosting.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$What technology is Wekan built on?$q$, $q$A JavaScript and Meteor framework stack for both the front end and back end.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Is Wekan GDPR-compliant?$q$, $q$When self-hosted on your own infrastructure, it can be run in a fully GDPR-compliant manner since you control the data.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Does Wekan have an API?$q$, $q$Yes, it exposes a REST API for integrations and automation.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Who maintains Wekan today?$q$, $q$Lauri Ojansivu has led development since December 2016, supported by a community of contributors.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Self-Hosted Team Task Boards$q$, $q$Teams that need full control over where their project data lives run Wekan on their own infrastructure.$q$, $q$Privacy-conscious teams and IT departments$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Educational and Nonprofit Project Management$q$, $q$Schools, nonprofits, and government bodies use Wekan as a free kanban tool that meets data sovereignty requirements.$q$, $q$Schools, nonprofits, and government organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Open-Source Project Coordination$q$, $q$Open-source communities track contributions and tasks on self-hosted Wekan boards.$q$, $q$Open-source project maintainers and communities$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited boards and users","Trello import","Docker and Snap deployment","REST API access","Community support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$overview$q$, $q$What Is Wekan$q$, 2, ARRAY[$q$Wekan is a free, open-source kanban board tool built as a self-hosted alternative to Trello. It was originally created around 2015 as LibreBoard by Maxime Quandalle and has been led since December 2016 by maintainer Lauri Ojansivu, with contributions from around 180 developers.$q$, $q$The application is built on a JavaScript and Meteor stack and deploys through Docker or Snap, letting organizations run it on their own servers or private infrastructure rather than relying on a third-party SaaS provider.$q$, $q$Wekan's board, list, and card structure closely mirrors Trello, and it supports direct import of existing Trello boards to simplify migration for teams switching platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core kanban functionality includes drag-and-drop cards, swimlanes, labels, checklists, due dates, attachments, comments, and user assignments, giving teams a familiar way to visualize and track work in progress.$q$, $q$Notifications alert users to mentions and changes, and templates let teams standardize board structures across projects to reduce setup time.$q$, $q$A REST API supports integrations and custom automations, and configurable public or private board visibility gives administrators control over who can see and edit each board.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Wekan is completely free and open source, with no license fees for the software itself. Costs are limited to the infrastructure needed to host and maintain a self-hosted instance.$q$, $q$There is no official first-party managed SaaS version from the core Wekan project, though some third-party companies offer paid managed hosting or commercial support contracts.$q$, $q$Because Wekan can be self-hosted entirely within an organization's own infrastructure, it can be run in a way that is fully GDPR-compliant, which is a key reason privacy-focused organizations choose it over commercial kanban SaaS tools.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8d61482f-100a-4065-95f7-81efc054d452', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
