INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Is WellSaid Labs free?$q$, $q$There is a free trial with limited generation minutes and no commercial rights; paid plans start at the Starter tier.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Can I use WellSaid voices commercially?$q$, $q$Yes, Starter, Pro, Business, and Enterprise plans all include full commercial usage rights.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Does WellSaid integrate with video editing tools?$q$, $q$Yes, it integrates with Adobe Premiere Pro and Adobe Express.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$How many voices does WellSaid offer?$q$, $q$More than 120 AI voices across a range of styles and accents.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Who founded WellSaid Labs?$q$, $q$WellSaid Labs spun out of the Allen Institute for AI (AI2) in Seattle and is generally cited as founded in 2018.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$What audio quality does WellSaid support?$q$, $q$Up to 48 kHz on the Pro plan and up to 96 kHz on the Enterprise plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Does WellSaid offer team collaboration?$q$, $q$Yes, Business and Enterprise plans include shared team workspaces and collaborator seats.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Where is WellSaid Labs based?$q$, $q$The company is headquartered in Seattle, Washington.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$eLearning and Corporate Training Narration$q$, $q$L&D teams generate consistent, professional narration for training courses without hiring voice talent for every update.$q$, $q$L&D teams and corporate training producers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Video and Podcast Voiceovers$q$, $q$Content creators produce voiceovers for marketing videos, explainer content, and podcasts directly inside editing tools.$q$, $q$Content creators, video editors, and marketers$q$, 1);
