INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Trial$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["3 downloaded minutes per month","10 minutes of generation","3 projects","No commercial usage rights"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Starter$q$, $q$$19/month ($10/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited generation","20 downloaded minutes per month","Full commercial rights","10 projects"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Pro$q$, $q$$49/month ($33/month billed annually)$q$, $q$monthly or annual$q$, NULL, $q$["180 downloaded minutes per month","Unlimited projects","Adobe Express integration","Up to 48 kHz audio"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Business$q$, $q$$160/month per user$q$, $q$annual$q$, NULL, $q$["Up to 5 seats","Team workspace","Live chat support","Adobe Premiere Pro integration"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["All languages and translation","Up to 96 kHz audio","SSO","Dedicated customer success manager"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$overview$q$, $q$What Is WellSaid Labs$q$, 2, ARRAY[$q$WellSaid Labs is an AI voice generation company that spun out of the Allen Institute for AI in Seattle and is generally cited as founded in 2018. It converts written text into realistic spoken audio using a library of more than 120 AI voices modeled on licensed recordings from real voice actors.$q$, $q$The platform is aimed at teams that need commercially usable voiceovers at scale, including corporate learning and development, marketing, and video production teams, and it emphasizes legal clarity around commercial usage rights since its voices are licensed rather than scraped.$q$, $q$WellSaid integrates directly into common creative workflows through plugins for Adobe Premiere Pro and Adobe Express, letting users generate voiceovers without switching tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users can select from 120-plus AI voices and adjust tone, pacing, pitch, and emphasis to control how a script sounds, then export finished audio in MP3, WAV, OGG, or caption/text formats.$q$, $q$Higher-tier plans unlock higher audio fidelity, up to 48 kHz on Pro and up to 96 kHz on Enterprise, along with team workspaces and collaborator seats for Business and Enterprise customers.$q$, $q$Direct integrations with Adobe Premiere Pro and Adobe Express let video editors generate and insert AI voiceovers directly inside their existing editing tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('219b186e-c25c-4fd3-b6af-3d5e32e6319e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$A free trial offers a limited amount of downloadable and generated audio with no commercial usage rights, intended for evaluation rather than production use.$q$, $q$Individual paid plans start with Starter at $19 per month (about $10 per month billed annually) with full commercial rights, and Pro at $49 per month (about $33 per month billed annually) with a larger download allowance and the Adobe Express integration.$q$, $q$Team plans are billed annually: Business costs $160 per month per user for up to five seats with a shared workspace, and Enterprise is custom-priced with all languages, translation, SSO, and a dedicated customer success manager.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Large File Transfers$q$, $q$Send files up to 1TB per transfer on the top-tier paid plan.$q$, 0);
