INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Download Notifications$q$, $q$Receive alerts when recipients download a shared file.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Reviews and Approvals$q$, $q$Collaborative feedback and approval tools for creative files.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Extremely simple, minimal-friction interface for sending large files$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Generous free tier that requires no account for basic transfers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Popular and trusted brand among creative professionals$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Useful add-ons like Portals and Reviews for creative collaboration$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$No restrictive file-type limits for common creative assets like video and design files$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Free plan has tight transfer limits within a rolling 30-day window$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Transfers expire, which can be a problem for long-term sharing or storage$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Fewer granular admin and security controls than enterprise file-sharing tools$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Ads and branding appear on free-tier transfer pages$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Is WeTransfer free?$q$, $q$Yes, a free plan supports smaller transfers within a rolling 30-day limit; larger, higher-volume transfers require a paid plan.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$How large a file can I send with WeTransfer?$q$, $q$Free transfers are capped at 2GB per send; the Ultimate paid plan supports transfers up to 1TB.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Do WeTransfer files expire?$q$, $q$Yes, free transfers typically expire after a set period unless the sender upgrades to a paid plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$What is a WeTransfer Portal?$q$, $q$A dedicated page for collecting files or feedback from multiple people, available on paid plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Is WeTransfer secure?$q$, $q$It offers password protection and expiring links; paid plans add more control over branding and access.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Where is WeTransfer based?$q$, $q$WeTransfer is headquartered in Amsterdam, Netherlands.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Can I brand my WeTransfer page?$q$, $q$Yes, custom branding for transfer pages and emails is available on paid plans.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Does WeTransfer offer storage, not just transfers?$q$, $q$Yes, paid plans include cloud storage in addition to transfer capability.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Sending Large Creative Files$q$, $q$Designers, photographers, and videographers share large project files with clients and collaborators.$q$, $q$Designers, photographers, and videographers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Client File Collection and Feedback$q$, $q$Agencies and freelancers use Portals and Reviews to collect files and structured feedback from clients.$q$, $q$Agencies and freelancers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Quick One-Off File Sharing$q$, $q$General consumers and business users send occasional large files without setting up a full account.$q$, $q$General consumers and business users$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 10 transfers or 3GB per rolling 30 days","2GB per transfer without an account"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Starter$q$, $q$$8/month$q$, $q$monthly$q$, NULL, $q$["300GB per rolling 30-day window","Cloud storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$Ultimate$q$, $q$$23/month ($19/month billed yearly)$q$, $q$monthly or annual$q$, NULL, $q$["Unlimited transfers up to 1TB each","Custom branding","Unlimited Portals and Reviews"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$overview$q$, $q$What Is WeTransfer$q$, 2, ARRAY[$q$WeTransfer is a large file transfer and sharing service founded in 2009 in Amsterdam, built around the idea of making it as simple as possible to send large files like photos, videos, and design assets without requiring recipients to create an account.$q$, $q$It became especially popular among creative professionals such as designers, photographers, and videographers for sharing project files with clients and collaborators, thanks to its minimal, frictionless interface.$q$, $q$Beyond basic transfers, WeTransfer has expanded into adjacent creative-collaboration tools, including Portals for collecting files or feedback and Reviews for structured approval workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users can send files as a shareable download link or directly by email, with options for password protection, expiration windows, and download notifications to track and secure transfers.$q$, $q$Portals give agencies and freelancers a dedicated page for collecting files or feedback from clients, while Reviews provide structured tools for gathering approvals on creative work.$q$, $q$Paid plans add persistent cloud storage in addition to transfer capability, along with custom branding for transfer pages and outgoing emails.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('de4e2a22-9bfb-45e0-b729-a24052dd6bfc', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The Free plan allows up to 10 transfers or 3GB of transfer volume within any rolling 30-day period, with individual transfers capped at 2GB when sent without an account.$q$, $q$The Starter plan costs $8 per month and raises the rolling 30-day transfer volume to 300GB, while the Ultimate plan costs $23 per month, or about $19 per month billed annually, and removes the rolling volume cap, supporting unlimited transfers of up to 1TB each.$q$, $q$Ultimate also adds custom branding for transfer pages and emails and unlimited use of Portals and Reviews, replacing the older Pro and Premium plan tiers that were folded into it during a prior pricing overhaul.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Visual Drag-and-Drop Editor$q$, $q$Build responsive web app user interfaces without writing code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$WeWeb AI$q$, $q$Generate UI components and layouts from natural-language prompts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Native Backend (WeWeb Tables)$q$, $q$A Postgres database with a spreadsheet-style UI, auto-generated CRUD APIs, and visual backend workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Any-Backend Connectivity$q$, $q$Connect to Supabase, Xano, REST, or GraphQL APIs instead of or alongside WeWeb's native backend.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Figma Import$q$, $q$Convert Figma designs directly into working application user interfaces.$q$, 4);
