INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Is WeWeb free?$q$, $q$Yes, a free seat plan is available with a limited AI token allowance and full visual editor access.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$What backends does WeWeb support?$q$, $q$Supabase, Xano, REST and GraphQL APIs, and its own native Postgres-based backend called WeWeb Tables.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Can I export code from WeWeb?$q$, $q$Yes, code export and GitHub sync are available on paid plans, reducing vendor lock-in.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Does WeWeb use AI?$q$, $q$Yes, WeWeb AI can generate UI components and layouts from prompts and imported Figma designs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Is WeWeb good for internal tools?$q$, $q$Yes, it is commonly used to build internal dashboards, portals, and SaaS front ends.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Who founded WeWeb?$q$, $q$Florian Briou, Marc Fabre, and Raphael Goldsztejn founded WeWeb, which is headquartered in Paris, France.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Does WeWeb require coding knowledge?$q$, $q$No coding is required for basic use, though custom logic and integrations benefit from technical familiarity.$q$, 6, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Internal Tools and Admin Dashboards$q$, $q$Startups and operations teams build internal apps and dashboards without a dedicated engineering team.$q$, $q$Startups and operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Client-Facing SaaS Front Ends$q$, $q$No-code agencies and SaaS founders build production front ends for client and commercial products.$q$, $q$No-code agencies and SaaS founders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Rapid MVP Prototyping$q$, $q$Product teams validate ideas quickly by building a functional front end before committing to full custom development.$q$, $q$Product teams validating new ideas$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["Limited AI token allowance","Full visual editor access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Essential$q$, $q$About $16 to $20/month$q$, $q$monthly$q$, NULL, $q$["GitHub sync","Larger AI token allowance","Custom domain support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Pro$q$, $q$About $42 to $50/month$q$, $q$monthly$q$, NULL, $q$["Unlimited seats","Larger AI token allocation","Team collaboration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$Partner$q$, $q$$67/user/month$q$, $q$monthly$q$, NULL, $q$["Free access to client workspaces","Project transfer","Referral commissions"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$overview$q$, $q$What Is WeWeb$q$, 2, ARRAY[$q$WeWeb is a no-code and low-code platform for building production-ready web applications, founded by Florian Briou, Marc Fabre, and Raphael Goldsztejn and headquartered in Paris, France. It started as a visual front-end builder that connects to virtually any backend, including Supabase, Xano, and custom APIs.$q$, $q$The platform has since expanded into a full-stack offering with its own native backend, WeWeb Tables, a Postgres database with a spreadsheet-style interface, auto-generated APIs, visual workflows, authentication, and storage, letting teams build both the front end and back end of an application in one place.$q$, $q$WeWeb AI, introduced in 2025, generates UI components and layouts from natural-language prompts, and the platform also supports importing designs directly from Figma to speed up interface development.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The visual drag-and-drop editor lets users build responsive web app interfaces without writing code, while custom logic and workflows can be added visually for more advanced app behavior.$q$, $q$WeWeb connects to almost any backend, including Supabase, Xano, and REST or GraphQL APIs, or teams can use WeWeb's own native Postgres-based backend for a fully self-contained stack.$q$, $q$For teams that want more control, WeWeb supports code export and GitHub sync, reducing vendor lock-in compared to fully closed no-code platforms.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WeWeb's pricing is split into seat plans, which govern editor access and building capabilities, and hosting plans, which govern deployment of live applications.$q$, $q$The Free seat plan includes a limited AI token allowance and full visual editor access; the Essential plan runs roughly $16 to $20 per month and adds GitHub sync, more AI tokens, and custom domain support; the Pro plan runs roughly $42 to $50 per month and adds unlimited seats and a larger AI token allocation.$q$, $q$A Partner plan, priced per user, is aimed at agencies and freelancers doing client work, and separate hosting tiers, from a free tier through Launch, Grow, and Scale, are required in addition to a paid seat plan to deploy production applications.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f43a5180-ad73-4b48-95ac-b2cd02106791', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
